16	function authHeaders(): Record<string, string> {
17	  const token = getToken();
18	  return token ? { Authorization: `Bearer ${token}` } : {};
19	}
20	
21	async function request<T>(
22	  method: string,
23	  path: string,
24	  body?: unknown
25	): Promise<T> {
26	  const headers: Record<string, string> = {
27	    "Content-Type": "application/json",
28	    ...authHeaders(),
29	  };
30	  const res = await fetch(path, {
31	    method,
32	    headers,
33	    body: body ? JSON.stringify(body) : undefined,
34	  });
35	  if (!res.ok) {
36	    const err: ErrorResponse = await res.json().catch(() => ({ error: "unknown" }));
37	    throw new ApiError(res.status, err.error);
38	  }
39	  return res.json() as Promise<T>;
40	}
41	
42	export class ApiError extends Error {
43	  status: number;
44	  code: string;
45	  constructor(status: number, code: string) {
46	    super(code);
47	    this.status = status;
48	    this.code = code;
49	  }
50	}
