1	import type { AuthUser } from "./types.ts";
2	
3	const TOKEN_KEY = "token";
4	const USER_KEY = "user";
5	
6	export function getStoredToken(): string | null {
7	  return localStorage.getItem(TOKEN_KEY);
8	}
9	
10	export function getStoredUser(): AuthUser | null {
11	  const raw = localStorage.getItem(USER_KEY);
12	  if (!raw) return null;
13	  try {
14	    return JSON.parse(raw) as AuthUser;
15	  } catch {
16	    return null;
17	  }
18	}
19	
20	export function storeAuth(token: string, user: AuthUser): void {
21	  localStorage.setItem(TOKEN_KEY, token);
22	  localStorage.setItem(USER_KEY, JSON.stringify(user));
23	}
24	
25	export function clearAuth(): void {
26	  localStorage.removeItem(TOKEN_KEY);
27	  localStorage.removeItem(USER_KEY);
28	}
29	
30	export function isAuthenticated(): boolean {
31	  return getStoredToken() !== null;
32	}
