1	import type { Shape, Operation, ShapePatch } from "./types.ts";
2	
3	/**
4	 * Apply an operation to a shapes array, returning a new array.
5	 */
6	export function applyOp(shapes: Shape[], op: Operation): Shape[] {
7	  switch (op.kind) {
8	    case "add":
9	      return [...shapes, op.shape];
10	    case "update":
11	      return shapes.map((s) =>
12	        s.id === op.shapeId ? { ...s, ...op.props } : s
13	      );
14	    case "delete":
15	      return shapes.filter((s) => s.id !== op.shapeId);
16	  }
17	}
18	
19	/**
20	 * Build the reverse operation for undo.
21	 * For update ops, only captures the fields that were changed (field-level LWW).
22	 */
23	/**
24	 * Build the reverse operation for undo.
25	 * Returns null if the reverse cannot be constructed (e.g. shape already gone).
26	 * Callers must skip pushing to the undo stack when null is returned.
27	 */
28	export function reverseOp(op: Operation, shapes: Shape[]): Operation | null {
29	  switch (op.kind) {
30	    case "add":
31	      return { kind: "delete", shapeId: op.shape.id };
32	
33	    case "delete": {
34	      const shape = shapes.find((s) => s.id === op.shapeId);
35	      if (!shape) {
36	        // Shape already gone — cannot build a valid reverse without a snapshot.
37	        return null;
38	      }
39	      return { kind: "add", shape: { ...shape } };
40	    }
41	
42	    case "update": {
43	      const shape = shapes.find((s) => s.id === op.shapeId);
44	      if (!shape) {
45	        // Shape not found — reverse would be a no-op, skip undo entry.
46	        return null;
47	      }
48	      // Only capture the old values of fields that are being changed
49	      const reverseProps: ShapePatch = {};
50	      for (const key of Object.keys(op.props) as (keyof ShapePatch)[]) {
51	        if (op.props[key] !== undefined) {
52	          (reverseProps as Record<string, unknown>)[key] = shape[key];
53	        }
54	      }
55	      return { kind: "update", shapeId: op.shapeId, props: reverseProps };
56	    }
57	  }
58	}
