1	import type { Shape } from "./types.ts";
2	
3	export interface CursorInfo {
4	  x: number;
5	  y: number;
6	  username: string;
7	  color: string;
8	}
9	
10	export interface SelectionState {
11	  shapeId: string;
12	  handles: { x: number; y: number; w: number; h: number }[];
13	}
14	
15	const HANDLE_SIZE = 8;
16	
17	export function renderScene(
18	  ctx: CanvasRenderingContext2D,
19	  shapes: Shape[],
20	  selection: SelectionState | null,
21	  cursors: Map<string, CursorInfo>,
22	  previewShape: Shape | null,
23	  canvasWidth: number,
24	  canvasHeight: number,
25	  dpr: number
26	): void {
27	  ctx.save();
28	  ctx.setTransform(dpr, 0, 0, dpr, 0, 0);
29	  ctx.clearRect(0, 0, canvasWidth, canvasHeight);
30	
31	  // Draw all shapes
32	  for (const shape of shapes) {
33	    drawShape(ctx, shape);
34	  }
35	
36	  // Draw preview shape
37	  if (previewShape) {
38	    drawShape(ctx, previewShape);
39	  }
40	
41	  // Draw selection
42	  if (selection) {
43	    const shape = shapes.find((s) => s.id === selection.shapeId);
44	    if (shape) {
45	      drawSelectionBox(ctx, shape);
46	    }
47	  }
48	
49	  // Draw remote cursors
50	  for (const [, cursor] of cursors) {
51	    drawCursor(ctx, cursor);
52	  }
53	
54	  ctx.restore();
55	}
56	
57	function drawShape(ctx: CanvasRenderingContext2D, shape: Shape): void {
58	  ctx.save();
59	  ctx.fillStyle = shape.fill || "transparent";
60	  ctx.strokeStyle = shape.stroke || "#000000";
61	  ctx.lineWidth = shape.strokeWidth;
62	
63	  switch (shape.type) {
64	    case "rectangle":
65	      if (shape.fill) {
66	        ctx.fillRect(shape.x, shape.y, shape.width, shape.height);
67	      }
68	      ctx.strokeRect(shape.x, shape.y, shape.width, shape.height);
69	      break;
70	
71	    case "ellipse": {
72	      const cx = shape.x + shape.width / 2;
73	      const cy = shape.y + shape.height / 2;
74	      const rx = Math.abs(shape.width / 2);
75	      const ry = Math.abs(shape.height / 2);
76	      ctx.beginPath();
77	      ctx.ellipse(cx, cy, rx, ry, 0, 0, Math.PI * 2);
78	      if (shape.fill) {
79	        ctx.fill();
80	      }
81	      ctx.stroke();
82	      break;
83	    }
84	
85	    case "line":
86	      ctx.beginPath();
87	      ctx.moveTo(shape.x, shape.y);
88	      ctx.lineTo(shape.x + shape.width, shape.y + shape.height);
89	      ctx.stroke();
90	      break;
91	
92	    case "text": {
93	      const fontSize = shape.fontSize || 16;
94	      ctx.font = `${fontSize}px sans-serif`;
95	      ctx.fillStyle = shape.fill || "#000000";
96	      ctx.fillText(shape.text || "", shape.x, shape.y + fontSize);
97	      if (shape.stroke && shape.strokeWidth > 0) {
98	        ctx.strokeStyle = shape.stroke;
99	        ctx.lineWidth = shape.strokeWidth;
100	        ctx.strokeText(shape.text || "", shape.x, shape.y + fontSize);
101	      }
102	      break;
103	    }
104	  }
105	
106	  ctx.restore();
107	}
108	
109	function drawSelectionBox(ctx: CanvasRenderingContext2D, shape: Shape): void {
110	  ctx.save();
111	  ctx.strokeStyle = "#0088ff";
112	  ctx.lineWidth = 1;
113	  ctx.setLineDash([4, 4]);
114	  ctx.strokeRect(shape.x - 2, shape.y - 2, shape.width + 4, shape.height + 4);
115	  ctx.setLineDash([]);
116	
117	  // Draw handles at corners
118	  const handles = getHandlePositions(shape);
119	  ctx.fillStyle = "#0088ff";
120	  for (const h of handles) {
121	    ctx.fillRect(h.x, h.y, h.w, h.h);
122	  }
123	
124	  ctx.restore();
125	}
126	
127	export function getHandlePositions(
128	  shape: Shape
129	): { x: number; y: number; w: number; h: number; corner: string }[] {
130	  const hs = HANDLE_SIZE;
131	  const half = hs / 2;
132	  return [
133	    { x: shape.x - half - 2, y: shape.y - half - 2, w: hs, h: hs, corner: "nw" },
134	    { x: shape.x + shape.width - half + 2, y: shape.y - half - 2, w: hs, h: hs, corner: "ne" },
135	    { x: shape.x - half - 2, y: shape.y + shape.height - half + 2, w: hs, h: hs, corner: "sw" },
136	    {
137	      x: shape.x + shape.width - half + 2,
138	      y: shape.y + shape.height - half + 2,
139	      w: hs,
140	      h: hs,
141	      corner: "se",
142	    },
143	  ];
144	}
145	
146	function drawCursor(ctx: CanvasRenderingContext2D, cursor: CursorInfo): void {
147	  ctx.save();
148	
149	  // Draw cursor arrow
150	  ctx.fillStyle = cursor.color;
151	  ctx.strokeStyle = "#ffffff";
152	  ctx.lineWidth = 1;
153	
154	  ctx.beginPath();
155	  ctx.moveTo(cursor.x, cursor.y);
156	  ctx.lineTo(cursor.x, cursor.y + 16);
157	  ctx.lineTo(cursor.x + 5, cursor.y + 12);
158	  ctx.lineTo(cursor.x + 10, cursor.y + 12);
159	  ctx.closePath();
160	  ctx.fill();
161	  ctx.stroke();
162	
163	  // Draw username label
164	  ctx.font = "11px sans-serif";
165	  const metrics = ctx.measureText(cursor.username);
166	  const labelX = cursor.x + 12;
167	  const labelY = cursor.y + 10;
168	  const padding = 3;
169	
170	  ctx.fillStyle = cursor.color;
171	  const rx = labelX - padding;
172	  const ry2 = labelY - 10 - padding;
173	  const rw = metrics.width + padding * 2;
174	  const rh = 14 + padding * 2;
175	  const r = 3;
176	  ctx.beginPath();
177	  ctx.moveTo(rx + r, ry2);
178	  ctx.lineTo(rx + rw - r, ry2);
179	  ctx.arcTo(rx + rw, ry2, rx + rw, ry2 + r, r);
180	  ctx.lineTo(rx + rw, ry2 + rh - r);
181	  ctx.arcTo(rx + rw, ry2 + rh, rx + rw - r, ry2 + rh, r);
182	  ctx.lineTo(rx + r, ry2 + rh);
183	  ctx.arcTo(rx, ry2 + rh, rx, ry2 + rh - r, r);
184	  ctx.lineTo(rx, ry2 + r);
185	  ctx.arcTo(rx, ry2, rx + r, ry2, r);
186	  ctx.closePath();
187	  ctx.fill();
188	
189	  ctx.fillStyle = "#ffffff";
190	  ctx.fillText(cursor.username, labelX, labelY);
191	
192	  ctx.restore();
193	}
194	
195	export function hitTest(shapes: Shape[], x: number, y: number): Shape | null {
196	  // Iterate in reverse z-order (topmost first)
197	  for (let i = shapes.length - 1; i >= 0; i--) {
198	    const s = shapes[i];
199	    if (isPointInShape(s, x, y)) {
200	      return s;
201	    }
202	  }
203	  return null;
204	}
205	
206	function isPointInShape(shape: Shape, px: number, py: number): boolean {
207	  const margin = 4;
208	  switch (shape.type) {
209	    case "rectangle":
210	    case "text":
211	      return (
212	        px >= shape.x - margin &&
213	        px <= shape.x + shape.width + margin &&
214	        py >= shape.y - margin &&
215	        py <= shape.y + shape.height + margin
216	      );
217	
218	    case "ellipse": {
219	      const cx = shape.x + shape.width / 2;
220	      const cy = shape.y + shape.height / 2;
221	      const rx = Math.abs(shape.width / 2) + margin;
222	      const ry = Math.abs(shape.height / 2) + margin;
223	      if (rx === 0 || ry === 0) return false;
224	      const dx = px - cx;
225	      const dy = py - cy;
226	      return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
227	    }
228	
229	    case "line": {
230	      // Check distance from point to line segment
231	      const x1 = shape.x;
232	      const y1 = shape.y;
233	      const x2 = shape.x + shape.width;
234	      const y2 = shape.y + shape.height;
235	      const dist = distToSegment(px, py, x1, y1, x2, y2);
236	      return dist <= shape.strokeWidth / 2 + margin + 4;
237	    }
238	
239	    default:
240	      return false;
241	  }
242	}
243	
244	function distToSegment(
245	  px: number,
246	  py: number,
247	  x1: number,
248	  y1: number,
249	  x2: number,
250	  y2: number
251	): number {
252	  const dx = x2 - x1;
253	  const dy = y2 - y1;
254	  const lenSq = dx * dx + dy * dy;
255	  if (lenSq === 0) return Math.sqrt((px - x1) ** 2 + (py - y1) ** 2);
256	  let t = ((px - x1) * dx + (py - y1) * dy) / lenSq;
257	  t = Math.max(0, Math.min(1, t));
258	  const projX = x1 + t * dx;
259	  const projY = y1 + t * dy;
260	  return Math.sqrt((px - projX) ** 2 + (py - projY) ** 2);
261	}
262	
263	export function hitTestHandle(
264	  shape: Shape,
265	  x: number,
266	  y: number
267	): string | null {
268	  const handles = getHandlePositions(shape);
269	  for (const h of handles) {
270	    if (x >= h.x && x <= h.x + h.w && y >= h.y && y <= h.y + h.h) {
271	      return h.corner;
272	    }
273	  }
274	  return null;
275	}
