1	import { useState } from "react";
2	import { signup, login, ApiError } from "../api.ts";
3	import { storeAuth } from "../authStore.ts";
4	
5	interface AuthProps {
6	  initialMode: "login" | "signup";
7	  onAuth: () => void;
8	}
9	
10	export default function Auth({ initialMode, onAuth }: AuthProps) {
11	  const [mode, setMode] = useState<"login" | "signup">(initialMode);
12	  const [username, setUsername] = useState("");
13	  const [email, setEmail] = useState("");
14	  const [password, setPassword] = useState("");
15	  const [error, setError] = useState("");
16	  const [loading, setLoading] = useState(false);
17	
18	  const handleSubmit = async (e: React.FormEvent) => {
19	    e.preventDefault();
20	    setError("");
21	    setLoading(true);
22	    try {
23	      if (mode === "signup") {
24	        const res = await signup({ username, email, password });
25	        storeAuth(res.token, res.user);
26	      } else {
27	        const res = await login({ username, password });
28	        storeAuth(res.token, res.user);
29	      }
30	      onAuth();
31	    } catch (err) {
32	      if (err instanceof ApiError) {
