4	  ShapeType,
5	  ShapePatch,
6	  Operation,
7	  UndoEntry,
8	  PresenceUser,
9	  ServerMessage,
10	  ClientMessage,
11	} from "../types.ts";
12	import { getStoredToken } from "../authStore.ts";
13	import { getCanvasDetail, ApiError } from "../api.ts";
14	import { renderScene, hitTest, hitTestHandle } from "../canvasRenderer.ts";
15	import type { CursorInfo } from "../canvasRenderer.ts";
