20	
21	interface CanvasPageProps {
22	  canvasId: string;
23	  onBack: () => void;
24	  onLogout: () => void;
25	}
26	
27	// Interaction mode during mouse drag
28	type DragMode =
29	  | { kind: "none" }
30	  | { kind: "draw"; startX: number; startY: number; previewShape: Shape }
31	  | {
32	      kind: "move";
33	      shapeId: string;
34	      startX: number;
35	      startY: number;
36	      origX: number;
37	      origY: number;
38	    }
39	  | {
40	      kind: "resize";
41	      shapeId: string;
42	      corner: string;
43	      startX: number;
44	      startY: number;
45	      origX: number;
46	      origY: number;
47	      origW: number;
48	      origH: number;
49	    };
50	
51	export default function CanvasPage({
52	  canvasId,
53	  onBack,
54	  onLogout,
55	}: CanvasPageProps) {
56	  // --- State stored in refs for high-frequency access ---
57	  const shapesRef = useRef<Shape[]>([]);
58	  const undoStackRef = useRef<UndoEntry[]>([]);
59	  const redoStackRef = useRef<UndoEntry[]>([]);
60	  const pendingOpsRef = useRef<Set<string>>(new Set());
61	  const cursorsRef = useRef<Map<string, CursorInfo>>(new Map());
62	  const onlineUsersRef = useRef<PresenceUser[]>([]);
63	  const selectedIdRef = useRef<string | null>(null);
64	  const dragModeRef = useRef<DragMode>({ kind: "none" });
65	  const wsRef = useRef<WebSocket | null>(null);
66	  const seqRef = useRef<number>(0);
67	  const canvasRef = useRef<HTMLCanvasElement | null>(null);
68	  const containerRef = useRef<HTMLDivElement | null>(null);
69	  const lastCursorSendRef = useRef<number>(0);
70	  const mountedRef = useRef(false);
71	  const wsInitReceivedRef = useRef(false);
72	
73	  // --- React state for UI that needs re-renders ---
74	  const [currentTool, setCurrentTool] = useState<Tool>("select");
75	  const [fillColor, setFillColor] = useState("#3498db");
76	  const [strokeColor, setStrokeColor] = useState("#000000");
77	  const [undoCount, setUndoCount] = useState(0);
78	  const [redoCount, setRedoCount] = useState(0);
79	  const [onlineUsers, setOnlineUsers] = useState<PresenceUser[]>([]);
80	  const [wsConnected, setWsConnected] = useState(false);
81	  const [error, setError] = useState("");
82	
83	  // --- Rendering ---
84	  const scheduleRender = useCallback(() => {
85	    const canvas = canvasRef.current;
86	    if (!canvas) return;
87	    const ctx = canvas.getContext("2d");
88	    if (!ctx) return;
89	    const dpr = window.devicePixelRatio || 1;
90	    const rect = canvas.getBoundingClientRect();
91	
92	    const selection = selectedIdRef.current
93	      ? {
94	          shapeId: selectedIdRef.current,
95	          handles: [],
96	        }
97	      : null;
98	
99	    const drag = dragModeRef.current;
100	    const preview = drag.kind === "draw" ? drag.previewShape : null;
101	
102	    renderScene(
103	      ctx,
104	      shapesRef.current,
105	      selection,
106	      cursorsRef.current,
107	      preview,
108	      rect.width,
109	      rect.height,
110	      dpr
111	    );
112	  }, []);
113	
114	  const renderRef = useRef(scheduleRender);
115	  renderRef.current = scheduleRender;
116	
117	  const requestRender = useCallback(() => {
118	    requestAnimationFrame(() => renderRef.current());
119	  }, []);
120	
121	  // --- WebSocket Send Helpers ---
122	  const sendWs = useCallback((msg: ClientMessage) => {
123	    const ws = wsRef.current;
124	    if (ws && ws.readyState === WebSocket.OPEN) {
125	      ws.send(JSON.stringify(msg));
126	    }
127	  }, []);
128	
129	  const sendOp = useCallback(
130	    (op: Operation) => {
131	      const ws = wsRef.current;
132	      if (!ws || ws.readyState !== WebSocket.OPEN) return; // drop if not connected
133	      const opId = crypto.randomUUID();
134	      // Apply optimistically
135	      shapesRef.current = applyOp(shapesRef.current, op);
136	      pendingOpsRef.current.add(opId);
137	      ws.send(JSON.stringify({ type: "op", op, opId } satisfies ClientMessage));
138	      requestRender();
139	    },
140	    [requestRender]
141	  );
142	
143	  const doAction = useCallback(
144	    (forward: Operation, reverse: Operation) => {
145	      undoStackRef.current = [...undoStackRef.current, { forward, reverse }];
146	      redoStackRef.current = [];
147	      setUndoCount(undoStackRef.current.length);
148	      setRedoCount(0);
149	      sendOp(forward);
150	    },
151	    [sendOp]
152	  );
153	
154	  // --- Undo/Redo ---
155	  const undo = useCallback(() => {
156	    const stack = undoStackRef.current;
157	    if (stack.length === 0) return;
158	    const entry = stack[stack.length - 1];
159	    undoStackRef.current = stack.slice(0, -1);
160	    redoStackRef.current = [...redoStackRef.current, entry];
161	    setUndoCount(undoStackRef.current.length);
162	    setRedoCount(redoStackRef.current.length);
163	    sendOp(entry.reverse);
164	  }, [sendOp]);
165	
166	  const redo = useCallback(() => {
167	    const stack = redoStackRef.current;
168	    if (stack.length === 0) return;
169	    const entry = stack[stack.length - 1];
170	    redoStackRef.current = stack.slice(0, -1);
171	    undoStackRef.current = [...undoStackRef.current, entry];
172	    setUndoCount(undoStackRef.current.length);
173	    setRedoCount(redoStackRef.current.length);
174	    sendOp(entry.forward);
175	  }, [sendOp]);
176	
177	  // --- Color change for selected shape ---
178	  const handleFillChange = useCallback(
179	    (color: string) => {
180	      setFillColor(color);
181	      const selId = selectedIdRef.current;
182	      if (selId) {
183	        const shape = shapesRef.current.find((s) => s.id === selId);
184	        if (shape) {
185	          const forward: Operation = {
186	            kind: "update",
187	            shapeId: selId,
188	            props: { fill: color },
189	          };
190	          const reverse: Operation = {
191	            kind: "update",
192	            shapeId: selId,
193	            props: { fill: shape.fill },
194	          };
195	          doAction(forward, reverse);
196	        }
197	      }
198	    },
199	    [doAction]
200	  );
201	
202	  const handleStrokeChange = useCallback(
203	    (color: string) => {
204	      setStrokeColor(color);
205	      const selId = selectedIdRef.current;
206	      if (selId) {
207	        const shape = shapesRef.current.find((s) => s.id === selId);
208	        if (shape) {
209	          const forward: Operation = {
210	            kind: "update",
211	            shapeId: selId,
212	            props: { stroke: color },
213	          };
214	          const reverse: Operation = {
215	            kind: "update",
216	            shapeId: selId,
217	            props: { stroke: shape.stroke },
218	          };
219	          doAction(forward, reverse);
220	        }
221	      }
222	    },
223	    [doAction]
224	  );
225	
226	  // --- Canvas coordinate helper ---
227	  const getCanvasCoords = useCallback(
228	    (e: MouseEvent): { x: number; y: number } => {
229	      const canvas = canvasRef.current;
230	      if (!canvas) return { x: 0, y: 0 };
