234	        y: e.clientY - rect.top,
235	      };
236	    },
237	    []
238	  );
239	
240	  // --- Mouse Handlers ---
241	  const handleMouseDown = useCallback(
242	    (e: MouseEvent) => {
243	      const { x, y } = getCanvasCoords(e);
244	
245	      // Text tool: prompt for text and create shape
246	      if (currentTool === "text") {
247	        const text = prompt("Enter text:");
248	        if (!text) return;
249	        const fontSize = 20;
250	        const newShape: Shape = {
251	          id: crypto.randomUUID(),
252	          type: "text",
253	          x,
254	          y,
255	          width: text.length * fontSize * 0.6,
256	          height: fontSize,
257	          fill: fillColor,
258	          stroke: strokeColor,
259	          strokeWidth: 0,
260	          text,
261	          fontSize,
262	        };
263	        const forward: Operation = { kind: "add", shape: newShape };
264	        const reverse: Operation = { kind: "delete", shapeId: newShape.id };
