311	          dragModeRef.current = { kind: "none" };
312	          requestRender();
313	        }
314	        return;
315	      }
316	
317	      // Drawing tools: start preview shape
318	      const shapeType = currentTool as ShapeType;
319	      const previewShape: Shape = {
320	        id: crypto.randomUUID(),
321	        type: shapeType,
322	        x,
